    "heroTitle": "Delaware annual report deadline and LLC annual tax",
    "heroSubtitle": "Delaware is a common place for filing confusion because corporations, foreign corporations, and Delaware LLCs do not follow the same rule. This page separates them so the word \"annual report\" does not accidentally get applied to Delaware LLC annual tax.",
    "lastReviewed": "March 11, 2026",
    "sourceBadge": "Source: Delaware Division of Corporations",
    "summaryTitle": "At a glance",
    "metrics": [
      {
        "label": "Domestic corporation",
        "text": "Annual report and franchise tax due March 1."
      },
      {
        "label": "Foreign corporation",
        "text": "Annual report due June 30 with a $125 filing fee."
      },
      {
        "label": "Delaware LLC",
        "text": "No annual report; $300 annual tax due June 1."
      }
    ],
    "summaryNoteHtml": null,
    "bodyHtml": "<section class=\"section surface\">\n          <div class=\"section__head\">\n            <p class=\"eyebrow\">Entity split</p>\n            <h2>Do not collapse these Delaware rules into one number</h2>\n          </div>\n          <div class=\"table-scroll\">\n            <table class=\"summary-table\">\n              <thead>\n                <tr>\n                  <th>Entity type</th>\n                  <th>Deadline</th>\n                  <th>Published filing fee or tax</th>\n                  <th>Late consequence</th>\n                </tr>\n              </thead>\n              <tbody>\n                <tr>\n                  <td>Domestic corporation, non-exempt</td>\n                  <td>March 1</td>\n                  <td>$50 annual report filing fee plus franchise tax</td>\n                  <td>$200 penalty plus 1.5% interest per month on tax and penalty</td>\n                </tr>\n                <tr>\n                  <td>Domestic corporation, exempt</td>\n                  <td>March 1</td>\n                  <td>$25 annual report filing fee</td>\n                  <td>$200 penalty if the annual report is not filed on time</td>\n                </tr>\n                <tr>\n                  <td>Foreign corporation</td>\n                  <td>June 30</td>\n                  <td>$125 annual report filing fee</td>\n                  <td>$125 penalty if the report is not filed by the due date</td>\n                </tr>\n                <tr>\n                  <td>Delaware LLC, LP, or GP</td>\n                  <td>June 1</td>\n                  <td>$300 annual tax</td>\n                  <td>$200 penalty plus 1.5% interest per month on tax and penalty</td>\n                </tr>\n              </tbody>\n            </table>\n          </div>\n        </section>\n\n<section class=\"detail-grid\">\n          <article class=\"detail-card\">\n            <h3>Why the old LLC annual-report phrasing was wrong</h3>\n            <p>\n              Delaware's own LLC, LP, and GP tax page says those entities do not file annual reports.\n              They pay a yearly tax instead. That distinction matters because many third-party pages\n              incorrectly frame the June 1 Delaware LLC tax as an annual report deadline.\n            </p>\n          </article>\n          <article class=\"detail-card\">\n            <h3>Filing path to use</h3>\n            <p>\n              Delaware directs both domestic corporation annual reports and alternative-entity annual\n              tax payments through the Division of Corporations online system. Use the official\n              portal rather than a solicitation or reminder letter that did not come from the state\n              or your registered agent.\n            </p>\n          </article>\n        </section>",
